using UnityEngine;

public class ShaderBasics : MonoBehaviour
{
    public Material glowMaterial;
    public Material outlineMaterial;
    public Material dissolveMaterial;
    public Material gradientMaterial;

    private SpriteRenderer spriteRenderer;

    void Start()
    {
        spriteRenderer = GetComponent<SpriteRenderer>();

        if (spriteRenderer != null)
        {
            // Default material
            Debug.Log("Current Material: " + spriteRenderer.material.name);
        }
    }

    void Update()
    {
        // Switch shaders with keys
        if (Input.GetKeyDown(KeyCode.Alpha1))
            SetShader(glowMaterial);
        if (Input.GetKeyDown(KeyCode.Alpha2))
            SetShader(outlineMaterial);
        if (Input.GetKeyDown(KeyCode.Alpha3))
            SetShader(dissolveMaterial);
        if (Input.GetKeyDown(KeyCode.Alpha4))
            SetShader(gradientMaterial);
    }

    void SetShader(Material material)
    {
        if (spriteRenderer != null && material != null)
        {
            spriteRenderer.material = material;
            Debug.Log("Shader changed to: " + material.name);
        }
    }

    // ---- Shader Methods ----

    public void SetGlowIntensity(float intensity)
    {
        if (glowMaterial != null)
        {
            glowMaterial.SetFloat("_GlowIntensity", intensity);
        }
    }

    public void SetDissolveAmount(float amount)
    {
        if (dissolveMaterial != null)
        {
            dissolveMaterial.SetFloat("_DissolveAmount", amount);
        }
    }

    public void SetColor(Color color)
    {
        if (spriteRenderer != null)
        {
            spriteRenderer.color = color;
        }
    }
}

